typedef struct {
    int starting;
    int no_of_edges;
} Node;

__kernel void BFS_1(__global const Node* graph_nodes,
                    __global const int* graph_edges,
                    __global char* graph_mask,
                    __global char* updating_graph_mask,
                    __global char* graph_visited,
                    __global int* cost,
                    const int no_of_nodes)
{
    int tid = get_global_id(0);
    if (tid >= no_of_nodes) return;

    if (graph_mask[tid]) {
        graph_mask[tid] = 0;
        int start = graph_nodes[tid].starting;
        int end = start + graph_nodes[tid].no_of_edges;
        int curr_cost = cost[tid];
        for (int i = start; i < end; i++) {
            int id = graph_edges[i];
            if (!graph_visited[id]) {
                cost[id] = curr_cost + 1;
                updating_graph_mask[id] = 1;
            }
        }
    }
}

__kernel void BFS_2(__global char* graph_mask,
                    __global char* updating_graph_mask,
                    __global char* graph_visited,
                    __global char* over,
                    const int no_of_nodes)
{
    int tid = get_global_id(0);
    if (tid >= no_of_nodes) return;

    if (updating_graph_mask[tid]) {
        graph_mask[tid] = 1;
        graph_visited[tid] = 1;
        *over = 1;
        updating_graph_mask[tid] = 0;
    }
}
